"""Manually trace one sigma update to compare with R."""

import numpy as np
import pandas as pd
import jax.numpy as jnp
import sys
sys.path.insert(0, 'omnilss/src')

from omnilss.distributions import resolve_family

# Load data generated by R
df = pd.read_csv("scripts/diagnostic/test_data_nbi.csv")
y = df['y'].values
x1 = df['x1'].values
n = len(y)

# Get family
family = resolve_family("NBI")

# Use R's fitted mu values (after first mu update in first outer iteration)
# From R trace: mu coefficients after first update should give deviance ~415.75
mu_coef_r = np.array([0.7903567, 0.7200105])
X_mu = np.column_stack([np.ones(n), x1])
mu = np.exp(X_mu @ mu_coef_r)

# Initial sigma (before any updates)
sigma_initial = 0.5 * np.ones(n)

print("=" * 70)
print("Manual Sigma Update Trace")
print("=" * 70)
print(f"Using R's fitted mu (after first mu update)")
print(f"Mu coefficients: {mu_coef_r}")
print(f"Initial sigma: {sigma_initial[0]:.6f}")
print("=" * 70)

# Compute initial deviance
dev_incr = np.asarray(family.g_dev_inc(y=y, mu=mu, sigma=sigma_initial), dtype=np.float64)
initial_dev = np.sum(dev_incr)
print(f"\nInitial deviance (with R's mu, initial sigma): {initial_dev:.6f}")
print("(R shows ~415.75 after mu update, before sigma update)")
print("=" * 70)

# Now manually do one sigma update following the RS algorithm
X_sigma = np.ones((n, 1))  # Intercept only for sigma

# Get link functions
link_fun = family.link_functions["sigma"]
link_inv = family.link_inverses["sigma"]
link_deriv_func = family.link_derivatives["sigma"]

# Get derivative functions
dldp = family.score_functions["sigma"]
d2ldp2 = family.hessian_functions["sigma"]

# Step 1: Compute eta
eta = np.asarray(link_fun(jnp.asarray(sigma_initial, dtype=jnp.float64)), dtype=np.float64)
print(f"\n1. Initial eta (log(sigma)): {eta[0]:.6f}")

# Step 2: Compute derivatives at initial sigma
first_deriv = np.asarray(dldp(y=y, mu=mu, sigma=sigma_initial), dtype=np.float64)
second_deriv = np.asarray(d2ldp2(y=y, mu=mu, sigma=sigma_initial), dtype=np.float64)
print(f"2. Score (first deriv): mean={np.mean(first_deriv):.6f}, sum={np.sum(first_deriv):.6f}")
print(f"   Hessian (second deriv): mean={np.mean(second_deriv):.6f}")

# Step 3: Compute link derivative
dmu_deta = np.asarray(link_deriv_func(jnp.asarray(eta, dtype=jnp.float64)), dtype=np.float64)
link_deriv = 1.0 / (dmu_deta + 1e-15)
print(f"3. Link derivative (deta/dsigma): {link_deriv[0]:.6f}")

# Step 4: Ensure second derivative is negative
second_deriv = np.where(second_deriv < -1e-15, second_deriv, -1e-15)

# Step 5: Compute working weights
working_weights = -(second_deriv / (link_deriv ** 2))
working_weights = np.clip(working_weights, 1e-10, 1e10)
print(f"4. Working weights: mean={np.mean(working_weights):.6f}")

# Step 6: Compute working response
offset = np.zeros(n)
working_response = (eta - offset) + first_deriv / (link_deriv * working_weights)
print(f"5. Working response: mean={np.mean(working_response):.6f}")

# Step 7: Fit weighted least squares
W = working_weights
sqrt_W = np.sqrt(W)
WX = X_sigma * sqrt_W[:, None]
Wy = working_response * sqrt_W

coef, _, _, _ = np.linalg.lstsq(WX, Wy, rcond=None)
print(f"6. Fitted coefficient (log(sigma)): {coef[0]:.6f}")

# Step 8: Update eta and sigma
eta_new = X_sigma @ coef + offset
sigma_new = np.asarray(link_inv(jnp.asarray(eta_new, dtype=jnp.float64)), dtype=np.float64)
print(f"7. New eta: {eta_new[0]:.6f}")
print(f"   New sigma: {sigma_new[0]:.6f}")

# Step 9: Compute new deviance
dev_incr_new = np.asarray(family.g_dev_inc(y=y, mu=mu, sigma=sigma_new), dtype=np.float64)
new_dev = np.sum(dev_incr_new)
print(f"8. New deviance: {new_dev:.6f}")
print(f"   Change: {initial_dev - new_dev:.6f}")

print("=" * 70)
print("\nExpected from R trace:")
print("  After 1st sigma iteration: ~406.25")
print("  After 5th sigma iteration: ~405.87")
print("  Final sigma: ~0.63")
print("=" * 70)
